const item = $input.first().json;
const days = item.days_since_cancel || 0;

let template = 'day1_empathy';
let coupon_code = null;
let suggested_coupon = null;

if (days <= 1) {
  template = 'day1_empathy';
} else if (days >= 2 && days <= 4) {
  template = 'day3_value';
} else if (days >= 5 && days <= 10) {
  template = 'day7_winback';
  coupon_code = 'COMEBACK30';
  suggested_coupon = '30% off';
} else if (days >= 11 && days <= 17) {
  template = 'day7_winback';
  coupon_code = 'COMEBACK50';
  suggested_coupon = '50% off';
} else if (days >= 18) {
  template = 'day14_final';
  coupon_code = 'FREERETURN';
  suggested_coupon = 'Primer mes gratis';
}

return [{
  json: {
    ...item,
    template,
    coupon_code,
    suggested_coupon,
    days_since_cancel: days
  }
}];

const item = $input.first().json;
const crypto = require('crypto');
const secret = $env.N8N_INTERNAL_SECRET;
const apiUrl = $env.API_URL || 'https://novavision-production.up.railway.app';

const path = '/internal/retention/email/send';
const method = 'POST';
const timestamp = Date.now().toString();
const correlationId = crypto.randomUUID();

const body = JSON.stringify({
  account_id: item.account_id,
  template: item.template,
  coupon_code: item.coupon_code || undefined
});

const bodyHash = crypto.createHash('sha256').update(body).digest('hex');
const payload = `${timestamp}\n${method}\n${path}\n${bodyHash}`;
const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(payload).digest('hex');

return [{
  json: {
    ...item,
    _api_url: `${apiUrl}${path}`,
    _body: body,
    _timestamp: timestamp,
    _signature: signature,
    _correlation_id: correlationId
  }
}];

const item = $input.first().json;
const success = item.statusCode === 200 || item.statusCode === 201 || item.ok === true;
const emoji = success ? '✅' : '❌';

console.log(`${emoji} Retention email: account=${item.account_id} template=${item.template} coupon=${item.coupon_code || 'none'} status=${success ? 'sent' : 'failed'}`);

return [{ json: { ...item, email_sent: success } }];

